/* mobile-first */
.card { padding: clamp(0.75rem, 2vw, 1.25rem); }
.button { min-block-size: 44px; min-inline-size: 44px; }
@media (min-width: 768px) {
  .card { grid-column: span 2; }
}

/* REJECTED */
.card { width: 360px; padding: 24px; }       /* fixed px (r3) */
@media (max-width: 768px) { .card { width: 100% } } /* desktop-first (r2) */
.button { min-height: 24px; }                  /* below 44px (r4) */
.hero { height: 100vh; }                       /* iOS issue (r5) */
